 1	import { useEffect } from "react";
 2	import {
 3	  Routes,
 4	  Route,
 5	  useNavigationType,
 6	  useLocation,
 7	} from "react-router-dom";
 8	import Desktop from "./pages/Desktop";
 9	
10	function App() {
11	  const action = useNavigationType();
12	  const location = useLocation();
13	  const pathname = location.pathname;
14	
15	  useEffect(() => {
16	    if (action !== "POP") {
17	      window.scrollTo(0, 0);
18	    }
19	  }, [action, pathname]);
20	
21	  useEffect(() => {
22	    let title = "";
23	    let metaDescription = "";
24	
25	    switch (pathname) {
26	      case "/":
27	        title = "";
28	        metaDescription = "";
29	        break;
30	    }
31	
32	    if (title) {
33	      document.title = title;
34	    }
35	
36	    if (metaDescription) {
37	      const metaDescriptionTag: HTMLMetaElement | null = document.querySelector(
38	        'head > meta[name="description"]'
39	      );
40	      if (metaDescriptionTag) {
41	        metaDescriptionTag.content = metaDescription;
42	      }
43	    }
44	  }, [pathname]);
45	
46	  return (
47	    <Routes>
48	      <Route path="/" element={<Desktop />} />
49	    </Routes>
50	  );
51	}
52	export default App;
