import { FunctionComponent } from "react";
import { Box } from "@mui/material";
import QuickActionIcon from "./QuickActionIcon";
import styles from "./TittleInfoLightPopover.module.css";
import type { CSSProperties } from "react";

export type QuickActionItemVariant = "Default" | "Hover" | "Active";

export type QuickActionItemProps = {
  className?: string;
  /** Whether to show the left category icon */
  showLeftIcon?: boolean;
  /** Whether to show the right arrow icon */
  showRightIcon?: boolean;
  /** Quick action title */
  title?: string;
  /** Quick action value or description */
  description?: string;
  /** Icon variant for the left icon */
  leftIconVariant?: "type 1" | "type 2";
  /** Icon variant for the right arrow icon */
  rightIconVariant?: "type 1" | "type 2";
  /** Path to the left icon image */
  leftIconSrc?: string;
  /** Background color of the left icon */
  leftIconBackground?: CSSProperties["backgroundColor"];
  /** Background color of the right icon */
  rightIconBackground?: CSSProperties["backgroundColor"];
  /** Background shorthand for the right icon */
  rightIconBackgroundFull?: CSSProperties["background"];
  /** Visual variant */
  variant?: QuickActionItemVariant;
  /** Click handler */
  onClick?: () => void;
};

/**
 * QuickActionItem — a quick action shortcut row displaying a category icon,
 * title, value/description, and a right-arrow navigation icon.
 * Used in the "Ações Rápidas" panel on the dashboard.
 */
const QuickActionItem: FunctionComponent<QuickActionItemProps> = ({
  className = "",
  variant = "Default",
  showLeftIcon = true,
  showRightIcon = true,
  title,
  description,
  leftIconVariant,
  rightIconVariant,
  leftIconSrc,
  leftIconBackground,
  rightIconBackground,
  rightIconBackgroundFull,
  onClick,
}) => {
  return (
    <Box
      className={[styles.shortcutItemWrapper, className].join(" ")}
      data-property1={variant}
      role="button"
      tabIndex={0}
      aria-label={title}
      onClick={onClick}
      onKeyDown={(e) => e.key === "Enter" && onClick?.()}
    >
      <Box className={styles.shortcutItem}>
        {!!showLeftIcon && (
          <QuickActionIcon
            variant={leftIconVariant}
            backgroundColor={leftIconBackground}
            iconSrc={leftIconSrc}
          />
        )}
        <Box className={styles.popoverTitleParent}>
          <div className={styles.popoverTitle}>{title}</div>
          <div className={styles.infoExplainingMore}>{description}</div>
        </Box>
        {!!showRightIcon && (
          <QuickActionIcon
            variant={rightIconVariant}
            backgroundColor={rightIconBackground}
            background={rightIconBackgroundFull}
            iconSrc="/Arrow-right.svg"
          />
        )}
      </Box>
    </Box>
  );
};

export default QuickActionItem;

