import { FunctionComponent } from "react";
import { Box } from "@mui/material";
import styles from "./FrameComponent1.module.css";

export type KpiCardProps = {
  /** KPI metric name */
  label: string;
  /** KPI metric display value (e.g., "R$ 4,82M") */
  value: string;
  /** Trend text (e.g., "12.6% mês passado") */
  trendText: string;
  /** Path to the category icon */
  iconSrc: string;
  /** Path to the trend arrow icon (up = positive, down = negative) */
  trendArrowSrc: string;
  /** CSS class for the outer container box */
  containerClass: string;
  /** CSS class for the inner content container */\
  innerContainerClass: string;
  /** CSS class for the icon filled wrapper */
  iconFilledClass: string;
  /** CSS class for the trend percentage text */
  trendTextClass: string;
};

/**
 * KpiCard — a single KPI metric card showing a category icon,
 * trend indicator, metric label, value, and a details link.
 */
const KpiCard: FunctionComponent<KpiCardProps> = ({
  label,
  value,
  trendText,
  iconSrc,
  trendArrowSrc,
  containerClass,
  innerContainerClass,
  iconFilledClass,
  trendTextClass,
}) => {
  return (
    <Box className={containerClass}>
      <Box className={innerContainerClass}>
        <Box className={styles.divflex}>
          <Box className={iconFilledClass}>
            <img className={styles.icon} alt="" src={iconSrc} />
          </Box>
          <Box className={styles.container3}>
            <Box className={styles.container4}>
              <img className={styles.arrowIcon} alt="" src={trendArrowSrc} />
            </Box>
            <Box className={styles.container5}>
              <div className={trendTextClass}>{trendText}</div>
            </Box>
          </Box>
        </Box>
        <Box className={styles.container6}>
          <Box className={styles.divmt6}>
            <Box className={styles.ptextSm}>
              <div className={styles.title}>{label}</div>
            </Box>
            <Box className={styles.pfontDisplay}>
              <div className={styles.value}>{value}</div>
            </Box>
          </Box>
        </Box>
      </Box>
      <Box className={styles.ptextXs}>
        <Box className={styles.container7}>
          <img className={styles.arrowIcon2} alt="" src="/Arrow-Icon1.svg" />
          <div className={styles.linkText}>Acessar mais detalhes</div>
        </Box>
      </Box>
    </Box>
  );
};

export default KpiCard;

