import { FunctionComponent } from "react";
import { Box } from "@mui/material";
import TopNavigationBar from "../components/TopNavigationBar";
import NavButton from "../components/NavButton";
import KpiCardsRow from "../components/KpiCardsRow";
import TrendsCard from "../components/TrendsCard";
import NpsSegment from "../components/NpsSegment";
import OperationsCard from "../components/OperationsCard";
import QuickActionItem from "../components/QuickActionItem";
import AiButton from "../components/AiButton";
import styles from "./Desktop.module.css";

// ─── Types ───────────────────────────────────────────────────────────────────

type FilterButtonData = {
  text: string;
  iconSrc: string;
  type: "Secondary" | "Ghost";
};

type NpsSegmentData = {
  label: string;
  value: string;
  gridColumn: "1" | "2" | "3";
  indicatorColor: string;
  valueWidth?: string;
  valueDisplay?: string;
  valueAlignItems?: string;
};

type QuickActionData = {
  title: string;
  description: string;
  leftIconSrc: string;
  leftIconBackground: string;
};

// ─── Static Data ─────────────────────────────────────────────────────────────

const FILTER_BUTTONS: FilterButtonData[] = [
  { text: "Visão Geral", iconSrc: "/Arrow-up-circle.svg", type: "Secondary" },
  { text: "Este Mês", iconSrc: "/Arrow-up-circle.svg", type: "Secondary" },
  { text: "Últimos 30 Dias", iconSrc: "/Arrow-up-circle.svg", type: "Secondary" },
  { text: "Trimestre", iconSrc: "/Arrow-up-circle.svg", type: "Secondary" },
  { text: "Por Categoria", iconSrc: "/Chevron-down.svg", type: "Secondary" },
