import Desktop from "./pages/Desktop";

/**
 * App — root router component.
 * Handles scroll-to-top on navigation and sets page title/meta per route.
 */
function App() {
  const action = useNavigationType();
  const location = useLocation();
  const { pathname } = location;

  // Scroll to top on forward navigation
  useEffect(() => {
    if (action !== "POP") {
      window.scrollTo(0, 0);
    }
  }, [action, pathname]);

  // Set page title and meta description per route
  useEffect(() => {
    let title = "";
    let metaDescription = "";

    switch (pathname) {
      case "/":
        title = "Dashboard — V-Commerce";
        metaDescription = "Painel de controle V-Commerce: visão geral de receita, pedidos, clientes e operações.";
        break;
      default:
        title = "V-Commerce";
        break;
    }

    if (title) {
      document.title = title;
    }

    if (metaDescription) {
      const metaTag: HTMLMetaElement | null = document.querySelector(
        'head > meta[name="description"]'
      );
      if (metaTag) {
        metaTag.content = metaDescription;
      }
    }
  }, [pathname]);

  return (
    <Routes>
      <Route path="/" element={<Desktop />} />
    </Routes>
  );
}

export default App;
